// Check subscription status
async function checkSubscription(userId) {
    try {
        const response = await fetch(`${billingServiceUrl}/api/users/${userId}/subscription`);
        const data = await response.json();
        return data.success && data.data?.active === true;
    }
    catch (error) {
        console.error('Error checking subscription:', error);
        return false;
    }
}
// Get room online count
async function getRoomOnlineCount(room) {
    try {
        const response = await fetch(`${chatServiceUrl}/api/rooms/online`);
        const data = await response.json();
        if (data.success && data.data) {
            return room === 'general' ? data.data.general.count : data.data.adult.count;
        }
    }
    catch (error) {
        console.error('Error getting room online count:', error);
    }
    return 0;
}
// Handle incoming messages
async function handleMessage(message) {
    if (!bot)
        return;
    const telegramId = message.from?.id;
    const chatId = message.chat.id;
    const text = message.text || '';
    const username = message.from?.username;
    const firstName = message.from?.first_name;
    if (!telegramId)
        return;
    if (text?.startsWith('/start')) {
        const promoCode = text.replace('/start ', '').trim();
        if (promoCode && promoCode !== '/start') {
            await handlePromoVisit(telegramId, promoCode);
        }
    }
    const user = await getOrCreateUser(telegramId, username, firstName);
    const banStatus = await isUserBanned(user.id);
    if (banStatus.banned) {
        const banText = banStatus.until
            ? `Вы заблокированы до ${banStatus.until.toLocaleString('ru-RU')}`
            : 'Вы заблокированы';
        await bot.sendMessage(chatId, banText + (banStatus.reason ? `\nПричина: ${banStatus.reason}` : ''));
        await updateUserState(user.id, 'BANNED', 'none');
        return;
    }
    const state = await getUserState(user.id);
    const currentState = state?.state || 'NEW';
    if (text?.startsWith('/start')) {
        await handleStartCommand(chatId, user, currentState);
        return;
    }
    if (text === '/menu' || text === '/help') {
        await showMenu(chatId, user.id);
        return;
    }
    switch (currentState) {
        case 'NEW':
        case 'REG_NAME':
            await handleRegistrationName(chatId, user, text);
            break;
        case 'REG_AGE':
            await handleRegistrationAge(chatId, user, text);
            break;
        case 'MENU':
            await handleMenuSelection(chatId, user, text);
            break;
        case 'IN_GENERAL':
            await handleRoomMessage(chatId, user, message, 'general');
            break;
        case 'IN_ADULT':
            await handleRoomMessage(chatId, user, message, 'adult');
            break;
        case 'BANNED':
            await bot.sendMessage(chatId, 'Вы заблокированы');
            break;
    }
}
